**Discord Bot Code for Slash Command 'ban' with Discord.js v14**
-------------------------------------------------------------

```javascript
const { Client, GatewayIntentBits, SlashCommandBuilder, PermissionsBitField } = require('discord.js');

const client = new Client({
  intents: [
    GatewayIntentBits.Guilds,
    GatewayIntentBits.GuildMembers,
    GatewayIntentBits.GuildBans,
  ],
});

const banCommand = new SlashCommandBuilder()
  .setName('ban')
  .setDescription('Ban a member from the server')
  .addUserOption((option) =>
    option
      .setName('member')
      .setDescription('The member to ban')
      .setRequired(true)
  )
  .addStringOption((option) =>
    option
      .setName('reason')
      .setDescription('The reason for the ban')
      .setRequired(false)
  );

client.on('ready', () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

client.on('interactionCreate', async (interaction) => {
  if (!interaction.isChatInputCommand()) return;

  if (interaction.commandName === 'ban') {
    const member = interaction.options.getMember('member');
    const reason = interaction.options.getString('reason') || 'No reason provided';

    if (!member) {
      await interaction.reply({ content: 'Invalid member provided.', ephemeral: true });
      return;
    }

    if (!interaction.member.permissions.has(PermissionsBitField.Flags.BanMembers)) {
      await interaction.reply({ content: 'Permission denied: BAN_MEMBERS.', ephemeral: true });
      return;
    }

    try {
      await member.ban({ reason });
      await interaction.reply({ content: `Banned ${member.user.tag} for ${reason}.` });
    } catch (error) {
      console.error(error);
      await interaction.reply({ content: 'Failed to ban member.', ephemeral: true });
    }
  }
});

client.login('YOUR_BOT_TOKEN');
```

**Explanation**

This code creates a Discord bot using Discord.js v14 with a single slash command, `ban`. The command includes a required `member` option and an optional `reason` option.

Upon executing the `ban` command, the bot checks if the user has the `BAN_MEMBERS` permission. If they do, the bot attempts to ban the specified member, replying with a success message upon completion. If the operation fails or the user lacks the necessary permissions, the bot sends an appropriate error message.

**Setup**

1. Replace `YOUR_BOT_TOKEN` with your bot's token from the Discord Developer Portal.
2. Install the required module by running `npm install discord.js`.
3. Run the code using `node index.js`.

**Note**

This is a simplified example. For reliability and security, always consider edge cases and error handling in your bot's implementation.

