Here is a refined C++ function that converts a Markdown-formatted string to an HTML-formatted string, handling basic Markdown elements like headers, emphasis (bold and italic), and links:

```cpp
#include <iostream>
#include <string>
#include <regex>

std::string markdownToHtml(const std::string& markdown) {
    std::string html = markdown;

    // Headers (e.g., # Header -> <h1>Header</h1>)
    std::regex headerRegex(R"(^(#{1,6})\s+(.+)$)", std::regex::multiline);
    html = std::regex_replace(html, headerRegex, [](const std::smatch& m) {
        int level = m[1].str().length();
        return "<h" + std::to_string(level) + ">" + m[2].str() + "</h" + std::to_string(level) + ">";
    });

    // Bold (e.g., **bold** -> <strong>bold</strong>)
    std::regex boldRegex(R"(\*\*(.+?)\*\*)");
    html = std::regex_replace(html, boldRegex, "<strong>$1</strong>");

    // Italic (e.g., *italic* -> <em>italic</em>)
    std::regex italicRegex(R"(\*(.+?)\*)");
    html = std::regex_replace(html, italicRegex, "<em>$1</em>");

    // Links (e.g., [link text](url) -> <a href="url">link text</a>)
    std::regex linkRegex(R"(\[([^\]]+)\]\(([^\)]+)\))");
    html = std::regex_replace(html, linkRegex, "<a href=\"$2\">$1</a>");

    // Paragraphs (add <p> tags around paragraphs)
    std::regex paragraphRegex(R"((?:\r\n|\r|\n){2,})");
    html = std::regex_replace(html, paragraphRegex, "</p>\n\n<p>");
    html = "<p>" + html + "</p>";

    return html;
}

int main() {
    std::string markdown = R"(
# Header 1
## Header 2

This is a **bold** text and this is an *italic* text.

Here is a [link](https://example.com).

Another paragraph.
)";

    std::string html = markdownToHtml(markdown);

    std::cout << html << std::endl;

    return 0;
}
```

### Explanation:
1. **Headers**: The function converts Markdown headers (`# Header`) to HTML headers (`<h1>Header</h1>`) using a regular expression that matches the number of `#` symbols.
2. **Bold**: It converts `**bold**` to `<strong>bold</strong>`.
3. **Italic**: It converts `*italic*` to `<em>italic</em>`.
4. **Links**: It converts `[link text](url)` to `<a href="url">link text</a>`.
5. **Paragraphs**: It wraps paragraphs with `<p>` tags by replacing double newlines with paragraph tags.

You can extend this function to handle more Markdown features as needed.

